import {
  Build,
  Component,
  Prop,
  State,
  Element,
  Method,
  h,
  Host,
  Watch
} from '@stencil/core';
import { setDefaultHostAttributes } from '@src/utils/kds-utils/attributes/attributeUtils';
import { Fragment } from '@src/utils/kds-utils/fragment';

interface KdsTextAreaHostElement extends HTMLElement {
  nativeElement: HTMLElement;
}

@Component({
  tag: 'kds-textarea',
  styleUrl: 'kds-textarea.css',
  shadow: false
})
export class KdsTextArea {
  @Element() hostEl: KdsTextAreaHostElement;

  /** Disables if present. */
  @Prop() readonly disabled?: boolean;

  /** Associates the field to a form element. */
  @Prop() readonly form?: string;

  /** Deprecated. Indicates the validity of the value. */
  @Prop() readonly ariaInvalid: string | null;

  /** Indicates the validity of the value. */
  @Prop() readonly invalid: string | null = 'false';

  /** Defines the maximum number of characters allowed. */
  @Prop() readonly maxlength?: number;

  /** Defines the minimum number of characters allowed. */
  @Prop() readonly minlength?: number;

  /** Sets the name. */
  @Prop() readonly name?: string;

  /** Displays helpful information for the user. */
  @Prop() readonly placeholder?: string;

  /** Sets to read-only if present. */
  @Prop() readonly readonly?: boolean;

  /** Requires value before submission. */
  @Prop() readonly required?: boolean;

  /** Contains the current value. */
  @Prop({ mutable: true }) value?: string;

  /** Sets a class to the rendered `<textarea>`. */
  @Prop() readonly textareaClass?: string;

  /** Contains the current number of characters entered. */
  @State() count: number = 0;

  @State() renderMaxLengthMessage: boolean = false;

  private nativeElement: HTMLElement;

  private onInput = (event: Event) => {
    const textArea = event.target as HTMLTextAreaElement;
    this.value = textArea.value;

    if (!isNaN(this.maxlength)) {
      this.count = textArea.value.length;
    }
  };

  componentWillLoad() {
    setDefaultHostAttributes(this.hostEl);
    this.ariaInvalid &&
    console.warn(
      'The `ariaInvalid` prop for kds-textarea is deprecated. Use `invalid` instead.'
    );
    this.count = this.value ? this.value.length : this.count;
  }

  componentDidLoad() {
    this.hostEl.nativeElement = this.nativeElement;
  }

  @Watch('maxlength')
  removeInlineStyle() {
    this.nativeElement.removeAttribute('style');
  }

  @Watch('ariaInvalid')
  logAriaWarning() {
    console.warn(
      'The `ariaInvalid` prop for kds-textarea is deprecated. Use `invalid` instead.'
    );
  }

  @Watch('value')
  updateCount() {
    if (!isNaN(this.maxlength)) {
      this.count = this.value.length;
    }
  }

  /**
   * Returns the native `<textarea>` element.
   */
  @Method()
  getNativeElement(): Promise<HTMLElement> {
    return Promise.resolve(this.nativeElement!);
  }

  checkLength() {
    this.renderMaxLengthMessage =
      this.value && this.value.length === this.maxlength;
  }

  render() {
    return (
      <Host class='kds-TextArea-wrapper'>
        <textarea
          class={{
            'kds-TextArea': true,
            'kds-TextArea--limited': Boolean(this.maxlength),
            'border-negative-less-prominent': this.ariaInvalid === 'true' || this.invalid === 'true',
            [this.textareaClass]: Boolean(this.textareaClass)
          }}
          aria-describedby='text-area-description'
          aria-invalid={this.ariaInvalid || this.invalid}
          disabled={this.disabled}
          form={this.form}
          maxlength={this.maxlength}
          minlength={this.minlength}
          name={this.name}
          onInput={(event) => this.onInput(event)}
          onKeyUp={() => this.checkLength()}
          onBlur={() => (this.renderMaxLengthMessage = false)}
          placeholder={this.placeholder}
          readonly={this.readonly}
          required={this.required}
          value={this.value}
          ref={(el: HTMLTextAreaElement) => (this.nativeElement = el)}
        />
        {this.maxlength && (
          <Fragment>
            <span
              aria-live='polite'
              id='text-area-description'
              test-id={Build.isDev && 'character-count-label'}
              class={{
                'kds-Text--xs kds-TextArea-CharacterLimit': true,
                'border-negative-less-prominent': this.ariaInvalid === 'true' || this.invalid === 'true'
              }}
              aria-hidden='true'
            >
              Character Limit: {this.count}{' '}
              <span class='screen-reader'>of</span>
              <span aria-hidden='true'>/</span> {this.maxlength}
            </span>
          </Fragment>
        )}
      </Host>
    );
  }
}
